// Minimal token-bucket in JavaScript
class TokenBucket {
  constructor(ratePerSec, capacity) {
    this.rate = ratePerSec;
    this.capacity = capacity;
    this.tokens = capacity;
    this.last = Date.now();
  }

  allow() {
    const now = Date.now();
    const delta = (now - this.last) / 1000;
    this.tokens = Math.min(this.capacity, this.tokens + delta * this.rate);
    this.last = now;
    if (this.tokens >= 1) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }
}

// usage
const bucket = new TokenBucket(5, 10); // 5 req/sec, burst 10
if (!bucket.allow()) {
  // reject or queue
  console.log('throttle');
}
